const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];

if (!rows.length) {
  return [{ json: { empty: true, message: 'project_config tab empty' } }];
}

const headers = rows[0].map((h) => String(h ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells || !cells.some((c) => String(c ?? '').trim())) continue;

  const row = {};
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  if (row.profile_url && !row.url) row.url = row.profile_url;
  if (row.urls && !row.url) row.url = row.urls;

  out.push({ json: row });
}

if (!out.length) {
  return [{ json: { empty: true, message: 'No data rows in project_config' } }];
}

return out;

const results = [];

for (const item of $input.all()) {
  const row = item.json;
  const active = String(row.active ?? 'true').trim().toLowerCase();
  if (active === 'false' || active === '0' || active === 'no') continue;

  const platform = String(row.platform || 'tiktok').trim().toLowerCase();
  const urlField = row.url || row.urls || row.profile_url || '';
  const urls = String(urlField)
    .split(/[\n,;]+/)
    .map((u) => u.trim())
    .filter(Boolean);

  for (const post_url of urls) {
    results.push({
      json: {
        post_url,
        platform,
        config_segment_hint: String(row.segment || '').trim(),
        notes: String(row.notes || '').slice(0, 500),
      },
    });
  }
}

if (!results.length) {
  return [{ json: { empty: true, message: 'No active URLs in project_config' } }];
}

return results;

const ALLOW = new Set('tiktok'.split(',').map((s) => s.trim().toLowerCase()).filter(Boolean));

const ALIASES = {
  facebook: 'fb_page',
  fb: 'fb_page',
  page: 'fb_page',
  group: 'fb_group',
  fb_group: 'fb_group',
  fb_page: 'fb_page',
  tiktok: 'tiktok',
  tt: 'tiktok',
};

function normPlatform(raw) {
  const key = String(raw || 'tiktok').trim().toLowerCase();
  return ALIASES[key] || key;
}

const out = [];
for (const item of $input.all()) {
  if (item.json.empty) {
    return [{ json: item.json }];
  }
  const platform = normPlatform(item.json.platform);
  if (!ALLOW.has(platform)) continue;
  out.push({
    json: {
      ...item.json,
      platform,
    },
  });
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: `No active URLs for platforms: ${[...ALLOW].join(', ')}`,
    },
  }];
}

return out;

const INTERVAL_DAYS = 7;

function handleFromUrl(url, platform) {
  const u = String(url || '').trim();
  if (platform === 'tiktok') {
    const m = u.match(/@([^/?#]+)/);
    return (m?.[1] || u).toLowerCase();
  }
  if (platform === 'fb_page' || platform === 'fb_group') {
    try {
      const path = new URL(u).pathname.replace(/^\//, '').split('/')[0];
      return path.toLowerCase();
    } catch {
      return u.toLowerCase();
    }
  }
  return u.toLowerCase();
}

const isManual = $execution?.mode === 'manual';
const data = $getWorkflowStaticData('global');
const state = data.channel_state || {};
const now = Date.now();
const ms = INTERVAL_DAYS * 24 * 60 * 60 * 1000;

const out = [];
let skipped = 0;

for (const item of $input.all()) {
  if (item.json.empty) return [item];

  const platform = String(item.json.platform || 'tiktok');
  const handle = handleFromUrl(item.json.post_url, platform);
  const prev = state[handle];

  if (!isManual && prev?.last_scraped_at) {
    const t = Date.parse(prev.last_scraped_at);
    if (Number.isFinite(t) && now - t < ms) {
      skipped += 1;
      continue;
    }
  }

  out.push({
    json: {
      ...item.json,
      channel_handle: handle,
    },
  });
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: `All channels skipped (scraped within ${INTERVAL_DAYS} days). Manual run bypasses this.`,
      skipped,
    },
  }];
}

return out;

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
const keys = {};

for (let i = 1; i < rows.length; i++) {
  const nk = String(rows[i][0] ?? '').trim();
  if (nk) keys[nk] = true;
  const pid = String(rows[i][1] ?? '').trim();
  if (pid) keys[pid] = true;
}

const data = $getWorkflowStaticData('global');
data.dedupe_keys = keys;

return [{
  json: {
    ok: true,
    dedupe_count: Object.keys(keys).length,
    tab: 'scrape_index',
  },
}];

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
const byHandle = {};

for (let i = 1; i < rows.length; i++) {
  const handle = String(rows[i][0] ?? '').trim().toLowerCase();
  if (!handle) continue;
  const at = String(rows[i][1] ?? '').trim();
  const pid = String(rows[i][2] ?? '').trim();
  const prev = byHandle[handle];
  if (!prev?.last_scraped_at) {
    byHandle[handle] = { last_scraped_at: at, last_post_id: pid };
    continue;
  }
  const prevT = Date.parse(prev.last_scraped_at);
  const rowT = Date.parse(at);
  if (Number.isFinite(rowT) && (!Number.isFinite(prevT) || rowT >= prevT)) {
    byHandle[handle] = { last_scraped_at: at, last_post_id: pid };
  }
}

const data = $getWorkflowStaticData('global');
data.channel_state = byHandle;

return [{
  json: {
    ok: true,
    channel_count: Object.keys(byHandle).length,
    tab: 'channel_state',
  },
}];

const data = $getWorkflowStaticData('global');
data.sl_stats = { sheet_ok: 0, sheet_fail: 0, qualified: 0, apify_empty: 0, not_qualified: 0, skipped_duplicate: 0, skipped_channel: 0 };
return $input.all();

