if ($itemIndex > 0) {
  return [];
}

const split = $('Loop Over URLs').item?.json || {};
const wrapItems = $('Wrap Apify Response').all().length
  ? $('Wrap Apify Response').all()
  : $('Wrap FB Response').all();
const wrap = wrapItems[0]?.json || {};

const handle = split.channel_handle || '';
if (!handle) {
  return [{ json: { ok: false, skip_channel_state: true } }];
}

const last_post_id = String(wrap.post_id || '').trim();

return [{
  json: {
    ok: true,
    channel_body: {
      values: [[
        handle,
        new Date().toISOString(),
        last_post_id,
        String(split.platform || ''),
      ]],
    },
    channel_handle: handle,
  },
}];

const config = $('Loop Over URLs').item?.json || $('Split URLs from Config').item?.json || {};
const apifyRaw = $input.first().json;

const items = Array.isArray(apifyRaw) ? apifyRaw : [apifyRaw];
const results = [];

for (const post of items) {
  if (!post || typeof post !== 'object') continue;
  if (post.noResults === true) continue;
  if (post.error || post.errorCode) continue;
  if (post.error && !post.id && !post.postId && !post.videoId) continue;

  const post_id =
    post.id ||
    post.postId ||
    post.videoId ||
    post.shortCode ||
    post.aweme_id ||
    String(post.url || config.post_url || '').split('/').filter(Boolean).pop() ||
    '';

  const channel = post.channel || post.authorMeta || post.author || {};
  const username = channel.username || channel.name || '';
  const post_url =
    post.url ||
    post.webVideoUrl ||
    post.link ||
    (username && post_id
      ? `https://www.tiktok.com/@${username}/video/${post_id}`
      : '') ||
    config.post_url ||
    '';

  const text =
    post.text ||
    post.desc ||
    post.description ||
    post.caption ||
    post.title ||
    '';

  results.push({
    json: {
      post_id: String(post_id),
      post_url: String(post_url),
      platform: config.platform || post.platform || 'tiktok',
      author_id: String(
        post.authorId || channel.id || post.author?.id || post.ownerId || ''
      ),
      text: String(text).slice(0, 50000),
      engagement: {
        play: Number(post.playCount ?? 0),
        likes: Number(post.diggCount ?? 0),
        comments: Number(post.commentCount ?? 0),
        shares: Number(post.shareCount ?? 0),
      },
      apify_item: post,
      config_notes: config.notes || '',
    },
  });
}

if (!results.length) {
  return [{
    json: {
      ok: false,
      error: 'APIFY_EMPTY',
      post_url: config.post_url,
      hint: 'Apify quota hoặc URL không có post — kiểm tra output node Apify Scrape',
    },
  }];
}

return results;

function safeKey(platform, postId) {
  const p = String(platform || 'unknown').replace(/[^a-z0-9_]/gi, '_');
  const id = String(postId || 'unknown').replace(/[^a-zA-Z0-9._-]/g, '_');
  return `apify:${p}:${id}`;
}

const data = $getWorkflowStaticData('global');
const keys = data.dedupe_keys || {};

const out = [];
let skipped = 0;

for (const item of $input.all()) {
  const j = item.json;
  if (j.error === 'APIFY_EMPTY') {
    out.push(item);
    continue;
  }
  const pid = String(j.post_id || '').trim();
  if (!pid) continue;

  const nk = safeKey(j.platform, pid);
  if (keys[nk] || keys[pid]) {
    skipped += 1;
    continue;
  }
  out.push({ json: { ...j, normalized_key_preview: nk } });
}

if (!out.length) {
  return [{
    json: {
      ok: false,
      error: 'APIFY_ALL_DUPLICATE',
      skipped,
      message: 'Tất cả post đã có trong scrape_index — bỏ qua Claude',
    },
  }];
}

return out;

const data = $getWorkflowStaticData('global');
if (!data.sl_stats) {
  data.sl_stats = { sheet_ok: 0, sheet_fail: 0, qualified: 0, apify_empty: 0, not_qualified: 0 };
}

for (const item of $input.all()) {
  const j = item.json;
  if (j.error === 'APIFY_EMPTY' || j.error === 'APIFY_NO_RESULTS') {
    data.sl_stats.apify_empty += 1;
  }
}

return $input.all();

const VERDICTS = new Set(['qualified', 'maybe', 'reject']);
const SEGMENTS = new Set([
  'noxh_income', 'valuation', 'sme_credit', 'general_inbound', 'unclassified',
]);
const STAGES = new Set(['awareness', 'consideration', 'decision']);
const HEAT = new Set(['low', 'medium', 'high']);

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  let t = (fenced ? fenced[1] : s).trim();
  const start = t.indexOf('{');
  const end = t.lastIndexOf('}');
  if (start >= 0 && end > start) t = t.slice(start, end + 1);
  return t;
}

function getLlmText(input) {
  const j = input.json || input;
  return j.content?.[0]?.text || j.message?.content || j.text || j.output || j;
}

function upstreamPost() {
  return (
    $('Filter New Posts').item?.json ||
    $('Wrap Apify Response').item?.json ||
    $('Wrap FB Response').item?.json ||
    {}
  );
}

const upstream = upstreamPost();
const raw = getLlmText($input.first());

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const verdict = String(parsed.verdict || 'reject').toLowerCase();
  if (!VERDICTS.has(verdict)) throw new Error('INVALID_VERDICT');

  const score = Number(parsed.score ?? 0);
  if (!Number.isFinite(score) || score < 0 || score > 100) throw new Error('INVALID_SCORE');

  const conv = parsed.conversation || {};
  const signals = parsed.content_signals || {};
  const segmentHint = String(signals.segment_hint || 'unclassified').toLowerCase();

  const intake_v1 = {
    intake_version: Number(parsed.intake_version || 1),
    verdict,
    score,
    reject_reason: parsed.reject_reason ? String(parsed.reject_reason).slice(0, 1000) : null,
    summary: String(parsed.summary || '').slice(0, 2000),
    conversation: {
      surface_topic: String(conv.surface_topic || '').slice(0, 500),
      explicit_questions: Array.isArray(conv.explicit_questions)
        ? conv.explicit_questions.map((q) => String(q).slice(0, 300)).slice(0, 8)
        : [],
      implicit_fears: Array.isArray(conv.implicit_fears)
        ? conv.implicit_fears.map((x) => String(x).slice(0, 200)).slice(0, 6)
        : [],
      misconceptions: Array.isArray(conv.misconceptions)
        ? conv.misconceptions.map((x) => String(x).slice(0, 200)).slice(0, 6)
        : [],
      journey_stage: STAGES.has(String(conv.journey_stage || '').toLowerCase())
        ? String(conv.journey_stage).toLowerCase()
        : 'consideration',
      audience_voice: String(conv.audience_voice || '').slice(0, 300),
    },
    content_signals: {
      pain_intensity: Math.min(100, Math.max(0, Number(signals.pain_intensity || score) || 0)),
      discussion_heat: HEAT.has(String(signals.discussion_heat || '').toLowerCase())
        ? String(signals.discussion_heat).toLowerCase()
        : 'medium',
      inbound_potential: String(signals.inbound_potential || 'low').slice(0, 40),
      segment_hint: SEGMENTS.has(segmentHint) ? segmentHint : 'unclassified',
      evidence_quotes: Array.isArray(signals.evidence_quotes)
        ? signals.evidence_quotes.map((q) => String(q).slice(0, 120)).slice(0, 3)
        : [],
      single_insight_clip: signals.single_insight_clip !== false,
      hook_candidate: String(signals.hook_candidate || '').slice(0, 120),
      cta_keyword_hint: String(signals.cta_keyword_hint || 'CHECKLIST').slice(0, 40),
    },
    compliance_flags: Array.isArray(parsed.compliance_flags)
      ? parsed.compliance_flags.map(String).slice(0, 8)
      : [],
  };

  return [{
    json: {
      ok: true,
      ...upstream,
      intake_v1,
      claude: {
        verdict,
        score,
        summary: intake_v1.summary,
        reject_reason: intake_v1.reject_reason,
        intake_v1,
      },
    },
  }];
} catch (e) {
  return [{
    json: {
      ok: false,
      parse_error: e.message,
      ...upstream,
      claude: {
        verdict: 'reject',
        score: 0,
        summary: '',
        reject_reason: 'parse_failed',
        intake_v1: null,
      },
    },
  }];
}

const data = $getWorkflowStaticData('global');
if (!data.sl_stats) {
  data.sl_stats = { sheet_ok: 0, sheet_fail: 0, qualified: 0, apify_empty: 0, not_qualified: 0 };
}

for (const item of $input.all()) {
  const j = item.json;
  if (j.ok && j.claude?.verdict === 'qualified') {
    data.sl_stats.qualified += 1;
  } else if (j.ok) {
    data.sl_stats.not_qualified += 1;
  }
}

return $input.all();

function safeKey(platform, postId) {
  const p = String(platform || 'unknown').replace(/[^a-z0-9_]/gi, '_');
  const id = String(postId || 'unknown').replace(/[^a-zA-Z0-9._-]/g, '_');
  return `apify:${p}:${id}`;
}

const item = $input.first().json;
if (!item.ok) {
  return [{ json: { ok: false, error: 'SKIP_NORMALIZE', message: item.parse_error || 'upstream_fail' } }];
}

const platform = String(item.platform || 'unknown').trim().toLowerCase();
const post_id = String(item.post_id || '').trim();
if (!post_id) {
  return [{ json: { ok: false, error: 'MISSING_POST_ID' } }];
}

const verdict = item.claude?.verdict || 'reject';
const score = Number(item.claude?.score ?? item.intake_v1?.score ?? 0);
const captured_at = new Date().toISOString();
const intake = item.intake_v1 || item.claude?.intake_v1 || null;

const status =
  verdict === 'qualified' ? 'qualified' : verdict === 'maybe' ? 'raw' : 'rejected';

const segmentHint = intake?.content_signals?.segment_hint;
const tags = ['unclassified', platform];
if (segmentHint && segmentHint !== 'unclassified') tags.push(segmentHint);

const record = {
  normalized_key: safeKey(platform, post_id),
  post_id,
  platform,
  post_url: String(item.post_url || ''),
  author_id: String(item.author_id || ''),
  text: String(item.text || '').slice(0, 50000),
  segment: 'unclassified',
  score,
  claude_verdict: verdict,
  interest_key: intake?.content_signals?.cta_keyword_hint
    ? String(intake.content_signals.cta_keyword_hint).toLowerCase().replace(/[^a-z0-9_]/g, '_').slice(0, 80)
    : 'unknown',
  status,
  captured_at,
  source: 'apify_social_listen',
  tags,
  meta: {
    intake_v1: intake,
    intake_at: intake ? captured_at : null,
    claude: item.claude,
    apify_preview: {
      post_id,
      post_url: item.post_url,
      text_len: (item.text || '').length,
      engagement: item.engagement || null,
    },
    config_notes: item.config_notes || '',
  },
};

return [{ json: { ok: true, record } }];

const item = $input.first().json;
if (!item.ok || !item.record) {
  return [{ json: { ok: false, error: item.error || 'SKIP_SHEET', message: item.message } }];
}

const r = item.record;
const tags = Array.isArray(r.tags) ? r.tags.join(',') : String(r.tags ?? '');
const meta = typeof r.meta === 'string' ? r.meta : JSON.stringify(r.meta ?? {}).slice(0, 50000);

return [{
  json: {
    ok: true,
    normalized_key: String(r.normalized_key ?? ''),
    post_id: String(r.post_id ?? ''),
    platform: String(r.platform ?? ''),
    post_url: String(r.post_url ?? ''),
    author_id: String(r.author_id ?? ''),
    text: String(r.text ?? '').slice(0, 50000),
    segment: String(r.segment ?? 'unclassified'),
    score: Number(r.score ?? 0),
    claude_verdict: String(r.claude_verdict ?? ''),
    interest_key: String(r.interest_key ?? 'unknown'),
    status: String(r.status ?? 'raw'),
    captured_at: String(r.captured_at ?? ''),
    source: String(r.source ?? 'apify_social_listen'),
    tags,
    meta,
  },
}];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'content_queue';

const HEADERS = [
  'normalized_key',
  'post_id',
  'platform',
  'post_url',
  'author_id',
  'text',
  'segment',
  'score',
  'claude_verdict',
  'interest_key',
  'status',
  'captured_at',
  'source',
  'tags',
  'meta',
];

function toRow(record) {
  const tags = Array.isArray(record.tags) ? record.tags.join(',') : String(record.tags ?? '');
  const meta =
    typeof record.meta === 'string' ? record.meta : JSON.stringify(record.meta ?? {}).slice(0, 50000);
  return [
    String(record.normalized_key ?? ''),
    String(record.post_id ?? ''),
    String(record.platform ?? ''),
    String(record.post_url ?? ''),
    String(record.author_id ?? ''),
    String(record.text ?? '').slice(0, 50000),
    String(record.segment ?? 'unclassified'),
    Number(record.score ?? 0),
    String(record.claude_verdict ?? ''),
    String(record.interest_key ?? 'unknown'),
    String(record.status ?? 'raw'),
    String(record.captured_at ?? ''),
    String(record.source ?? 'apify_social_listen'),
    tags,
    meta,
  ];
}

async function sheetRequest(opts) {
  return this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    json: true,
    ...opts,
  });
}

const base = `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}`;
const readRange = `${TAB}!A:O`;

let existingByKey = new Map();
let nextAppendRow = 2;

try {
  const getRes = await sheetRequest.call(this, {
    method: 'GET',
    url: `${base}/values/${encodeURIComponent(readRange)}`,
  });
  const rows = getRes.values || [];

  if (!rows.length) {
    await sheetRequest.call(this, {
      method: 'PUT',
      url: `${base}/values/${encodeURIComponent(`${TAB}!A1:O1`)}?valueInputOption=USER_ENTERED`,
      body: { values: [HEADERS] },
    });
  } else {
    const headerRow = rows[0].map((h) => String(h ?? '').trim().toLowerCase());
    const nkIdx = headerRow.indexOf('normalized_key');
    const keyCol = nkIdx >= 0 ? nkIdx : 0;
    for (let i = 1; i < rows.length; i++) {
      const nk = String(rows[i][keyCol] ?? '').trim();
      if (nk) existingByKey.set(nk, i + 1);
    }
    nextAppendRow = rows.length + 1;
  }
} catch (e) {
  throw new Error(
    `Sheet read failed (${TAB}): ${e.message}. Tạo tab trước — xem SHEET_CONTENT_QUEUE_SETUP.md`
  );
}

const results = [];

for (const item of $input.all()) {
  if (!item.json.ok || !item.json.record) {
    results.push({ json: { ok: false, error: 'SKIP_SHEET', message: item.json.error } });
    continue;
  }

  const record = item.json.record;
  const nk = record.normalized_key;
  const rowValues = toRow(record);
  const existingRow = existingByKey.get(nk);

  try {
    if (existingRow) {
      const updateRange = `${TAB}!A${existingRow}:O${existingRow}`;
      await sheetRequest.call(this, {
        method: 'PUT',
        url: `${base}/values/${encodeURIComponent(updateRange)}?valueInputOption=USER_ENTERED`,
        body: { values: [rowValues] },
      });
      results.push({
        json: {
          ok: true,
          storage: 'sheet_content_queue',
          sheet_row: existingRow,
          action: 'update',
          normalized_key: nk,
          record,
        },
      });
    } else {
      await sheetRequest.call(this, {
        method: 'POST',
        url: `${base}/values/${encodeURIComponent(`${TAB}!A:O`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
        body: { values: [rowValues] },
      });
      existingByKey.set(nk, nextAppendRow);
      results.push({
        json: {
          ok: true,
          storage: 'sheet_content_queue',
          sheet_row: nextAppendRow,
          action: 'create',
          normalized_key: nk,
          record,
        },
      });
      nextAppendRow += 1;
    }
  } catch (e) {
    results.push({
      json: { ok: false, error: 'SHEET_WRITE', message: e.message, normalized_key: nk },
    });
  }
}

return results;

const data = $getWorkflowStaticData('global');
if (!data.sl_stats) {
  data.sl_stats = { sheet_ok: 0, sheet_fail: 0, qualified: 0, apify_empty: 0, not_qualified: 0 };
}

const row = $input.first().json;
const nk = row.normalized_key || $('Prepare Sheet Append').item?.json?.normalized_key;

if (nk) {
  data.sl_stats.sheet_ok += 1;
  return [{
    json: {
      ok: true,
      storage: 'sheet_content_queue',
      normalized_key: nk,
      action: row.action || 'upsert',
    },
  }];
}

data.sl_stats.sheet_fail += 1;
return [{ json: { ok: false, error: 'SHEET_UPSERT', message: 'Google Sheets node returned no normalized_key' } }];

const item = $input.first().json;
const record = $('Normalize Content Record').item?.json?.record;
const nk = item.normalized_key || record?.normalized_key;
if (!nk || !record) {
  return [{ json: { ok: false, skip_index: true } }];
}

const eng = record.meta?.engagement || record.meta?.apify_preview || {};

return [{
  json: {
    ok: true,
    index_body: {
      values: [[
        nk,
        String(record.post_id ?? ''),
        String(record.platform ?? ''),
        String(record.source ?? 'apify_social_listen'),
        new Date().toISOString(),
        JSON.stringify({ score: record.score, claude_verdict: record.claude_verdict }).slice(0, 500),
      ]],
    },
    normalized_key: nk,
  },
}];

const item = $input.first().json;
const record = item.record || item.json?.record;

if (!record?.normalized_key) {
  return [{ json: { drive_skip: true, reason: 'no record' } }];
}

const folderId = '1iBjsrXLYmHfOHMQaAfLmZGug2kN0314D';
if (!folderId) {
  return [{ json: { drive_skip: true, reason: 'backup disabled' } }];
}

const safeName = String(record.normalized_key).replace(/[^a-zA-Z0-9._-]/g, '_');
const fileName = `apify_raw/${safeName}.json`;
const content = JSON.stringify(record, null, 2);
const binaryData = Buffer.from(content, 'utf8').toString('base64');

return [{
  json: {
    fileName,
    normalized_key: record.normalized_key,
    drive_folder_id: folderId,
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'application/json',
      fileName: `${safeName}.json`,
    },
  },
}];

const data = $getWorkflowStaticData('global');
const stats = data.sl_stats || {};
let hint = null;
if ((stats.sheet_ok || 0) === 0 && (stats.apify_empty || 0) > 0) {
  hint = 'Apify trả rỗng — kiểm tra token/URL hoặc kênh đã quét trong 7 ngày';
} else if ((stats.sheet_ok || 0) === 0 && (stats.qualified || 0) === 0) {
  hint = 'Không có bài qualified — duplicate/reject hoặc ngách ngoài BĐS';
} else if ((stats.sheet_ok || 0) === 0 && (stats.qualified || 0) > 0) {
  hint = 'Có qualified nhưng Sheet chưa ghi — gán googleApi trên Sheet Upsert';
}
return [{ json: {
  ok: true,
  workflow: 'social-listening-tiktok',
  sheet_upserted: stats.sheet_ok || 0,
  stats,
  hint,
  finished_at: new Date().toISOString(),
}}];
